SELECT component_id, COUNT(*) AS total_tests
FROM component_tests
GROUP BY component_id;

SELECT COUNT(test_id) 
FROM component_tests 
WHERE frequency = 100;

SELECT operator_id, access_date, access_status 
FROM security_access 
WHERE access_level = 'read-write';

SELECT test_id, component_id, vgdc_voltage, test_timestamp 
FROM component_tests
ORDER BY test_timestamp;

SELECT * 
FROM component_tests 
WHERE test_id > 5;

SELECT COUNT(*) AS NumberOfAnomaliesDetected 
FROM test_results 
WHERE anomaly_detected = 1;
